import { IClosable, IReadable, IWritable } from '@fuman/io';
import { Readable, Writable } from 'node:stream';
/** convert a node Readable stream to a fuman IReadable */
export declare function nodeReadableToFuman(stream: Readable): IReadable & IClosable;
/** convert a fuman Readable stream to a node Readable stream */
export declare function fumanReadableToNode(stream: IReadable): Readable;
/** convert a node Writable stream to a fuman IWritable */
export declare function nodeWritableToFuman(writable: Writable): IWritable & IClosable;
/** convert a fuman Writable stream to a node Writable stream */
export declare function fumanWritableToNode(writable: IWritable): Writable;
